import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-settings.e7FrcLCc.js";const s=JSON.parse(`{"title":"Установлення Fabric на macOS","description":"Покрокова інструкція щодо встановлення Fabric на macOS.","frontmatter":{"title":"Установлення Fabric на macOS","description":"Покрокова інструкція щодо встановлення Fabric на macOS.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"uk_ua/players/installing-fabric/macos.md","filePath":"translated/uk_ua/players/installing-fabric/macos.md","lastUpdated":1770561656000}`);var c={name:`uk_ua/players/installing-fabric/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установлення Fabric на macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Установлення Fabric на macOS”">​</a></h1><div class="info custom-block"><p class="custom-block-title">ПЕРЕДУМОВИ</p><p>Можливо, вам знадобиться <a href="./../installing-java/macos">встановити Java</a> перед запуском <code>.jar</code>.</p></div><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Завантаження встановлювача Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Завантаження встановлювача Fabric”">​</a></h2><p>Завантажте версію <code>.jar</code> встановлювача Fabric з <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">сайту Fabric</a>, натиснувши <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запустіть встановлювач Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запустіть встановлювач Fabric”">​</a></h2><p>Перш ніж запустити встановлювач, закрийте Minecraft та запускач Minecraft.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Ви можете отримати попередження про те, що Apple не може перевірити <code>.jar</code>. Щоб обійти це, відкрийте Налаштування системи &gt; Конфіденційність і безпека та натиснути <code>Усе одно відкрити</code>. Підтвердьте та введіть пароль адміністратора, якщо буде запропоновано.</p><p><img src="/assets/players/installing-fabric/macos-settings.png" alt="Налаштування системи MacOS" loading="lazy"></p></div><p>Коли ви відкриєте встановлювач, ви повинні побачити такий екран:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Установлювач Fabric із виділеним «Установити»" loading="lazy"></p><p>Виберіть потрібну версію Minecraft і натисніть <code>Установити</code>. Переконайтеся, що вибрано <code>Створити інсталяцію</code>.</p><h3 id="installing-via-homebrew" tabindex="-1">Установлення через Homebrew <a class="header-anchor" href="#installing-via-homebrew" aria-label="Permalink to “Установлення через Homebrew”">​</a></h3><p>Якщо у вас уже встановлено <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a>, ви можете встановити встановлювач Fabric за допомогою <code>brew</code>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-finish-setup" tabindex="-1">3. Кінцеве налаштування <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Кінцеве налаштування”">​</a></h2><p>Після завершення встановлення відкрийте запускач Minecraft. Потім виберіть інсталяцію Fabric зі спадного списку версій і натисніть «Грати».</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Запускач Minecraft з вибраною інсталяцією Fabric" loading="lazy"></p><p>Тепер ви можете додавати моди до своєї гри. Перегляньте посібник <a href="./../finding-mods">пошуку надійних модів</a>, щоб дізнатися більше.</p><p>Якщо у вас виникнуть проблеми, не соромтеся звертатися по допомогу до <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> на каналі <code>#player-support</code>.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};